// --- types.d.ts ---
/**
 * Weather Card Component Types
 * All shared interfaces for the weather card component
 */

export interface ForecastDay {
  /** Day abbreviation (e.g., "Mon", "Tue") */
  day: string;
  /** Weather condition icon/emoji (e.g., "☀️", "⛅", "🌧️") */
  icon: string;
  /** High temperature for the day */
  high: number;
  /** Low temperature for the day */
  low: number;
}

export interface Props {
  /** City name to display */
  city: string;
  /** Current temperature value */
  temperature: number;
  /** Weather condition (e.g., "Sunny", "Cloudy", "Rainy", "Snowy") */
  condition: string;
  /** Humidity percentage (0-100) */
  humidity: number;
  /** Wind speed (in km/h or mph depending on context) */
  windSpeed: number;
  /** Temperature unit: "C" for Celsius or "F" for Fahrenheit */
  unit?: string;
  /** Array of 5-day forecast data */
  forecast: ForecastDay[];
}

export interface HookReturn {
  /** Mapped weather condition to emoji/icon string */
  conditionIcon: string;
  /** Formatted temperature string with unit */
  temperatureDisplay: string;
  /** Formatted humidity display */
  humidityDisplay: string;
  /** Formatted wind speed display */
  windSpeedDisplay: string;
}

export interface CurrentConditionProps {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition text */
  condition: string;
  /** Weather condition icon/emoji */
  icon: string;
  /** Temperature unit (C or F) */
  unit?: string;
}

export interface DetailsGridProps {
  /** Humidity percentage */
  humidity: number;
  /** Humidity formatted display string */
  humidityDisplay: string;
  /** Wind speed value */
  windSpeed: number;
  /** Wind speed formatted display string */
  windSpeedDisplay: string;
}

export interface ForecastStripProps {
  /** Array of 5-day forecast data */
  forecast: ForecastDay[];
  /** Temperature unit (C or F) for display */
  unit?: string;
}

export interface ForecastItemProps {
  /** Day abbreviation */
  day: string;
  /** Weather icon/emoji */
  icon: string;
  /** High temperature */
  high: number;
  /** Low temperature */
  low: number;
  /** Temperature unit for display */
  unit?: string;
}


// --- constants.ts ---
// constants.ts

/**
 * Weather condition to icon mapping
 * Maps various weather conditions to appropriate emoji symbols
 */
export const WEATHER_CONDITION_ICONS: Record<string, string> = {
  sunny: "☀️",
  clear: "☀️",
  cloudy: "☁️",
  overcast: "☁️",
  rainy: "🌧️",
  rain: "🌧️",
  snowy: "❄️",
  snow: "❄️",
  stormy: "⛈️",
  thunderstorm: "⛈️",
  "partly cloudy": "⛅",
  windy: "💨",
  fog: "🌫️",
  foggy: "🌫️",
};

/**
 * Default fallback icon for unrecognized weather conditions
 */
const DEFAULT_WEATHER_ICON = "🌤️";

/**
 * Get weather icon/emoji for a given condition
 * Normalizes input and looks up in weather condition icons mapping
 * @param condition - Weather condition string
 * @returns Weather emoji/icon or default fallback
 */
export function getWeatherIcon(condition: string): string {
  const normalized = condition.trim().toLowerCase();
  return WEATHER_CONDITION_ICONS[normalized] ?? DEFAULT_WEATHER_ICON;
}

/**
 * Formatting constants used throughout the weather card component
 */
export const FORMATTING_CONSTANTS = {
  /** Default temperature unit */
  DEFAULT_UNIT: "C",

  /** Temperature suffix by unit */
  TEMPERATURE_SUFFIX: {
    C: "°C",
    F: "°F",
  },

  /** Humidity percentage suffix */
  HUMIDITY_SUFFIX: "%",

  /** Wind speed suffix for metric system */
  WIND_SPEED_SUFFIX_METRIC: "km/h",

  /** Wind speed suffix for imperial system */
  WIND_SPEED_SUFFIX_IMPERIAL: "mph",

  /** Number of days in forecast */
  FORECAST_DAYS_COUNT: 5,
};


// --- hooks.ts ---
// hooks.ts
import { Props, HookReturn } from './types';

/**
 * Custom React hook for formatting weather data and mapping conditions to icons
 * @param props - Weather props containing temperature, condition, humidity, windSpeed, unit, and forecast
 * @returns HookReturn object with formatted display strings and condition icon
 */
export function useComponent(props: Props): HookReturn {
  const { temperature, condition, humidity, windSpeed, unit = 'C' } = props;

  // 1. Map weather condition to icon/emoji
  const conditionIcon = getWeatherIcon(condition);

  // 2. Format temperature with unit
  const temperatureDisplay = formatTemperature(temperature, unit);

  // 3. Format humidity percentage
  const humidityDisplay = formatHumidity(humidity);

  // 4. Format wind speed with appropriate unit
  const windSpeedDisplay = formatWindSpeed(windSpeed, unit);

  return {
    conditionIcon,
    temperatureDisplay,
    humidityDisplay,
    windSpeedDisplay,
  };
}

/**
 * Map weather condition strings to emoji icons
 */
function getWeatherIcon(condition: string): string {
  const conditionMap: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    overcast: '☁️',
    'partly cloudy': '⛅',
    rainy: '🌧️',
    rain: '🌧️',
    thunderstorm: '⛈️',
    snowy: '❄️',
    snow: '❄️',
    foggy: '🌫️',
    fog: '🌫️',
    windy: '💨',
  };

  const normalizedCondition = condition.toLowerCase().trim();
  return conditionMap[normalizedCondition] || '🌤️';
}

/**
 * Format temperature with unit symbol
 */
function formatTemperature(temperature: number, unit: string): string {
  const temp = Math.round(temperature);
  return `${temp}°${unit}`;
}

/**
 * Format humidity as percentage
 */
function formatHumidity(humidity: number): string {
  const humidityValue = Math.max(0, Math.min(100, humidity));
  return `${Math.round(humidityValue)}%`;
}

/**
 * Format wind speed with appropriate unit based on temperature unit
 */
function formatWindSpeed(windSpeed: number, unit: string): string {
  const speed = Math.round(windSpeed);
  // If unit is F (Fahrenheit context), use mph; otherwise use km/h (metric)
  const speedUnit = unit === 'F' ? 'mph' : 'km/h';
  return `${speed} ${speedUnit}`;
}


