// components/CurrentCondition.tsx
import React from 'react';
import { Stack, Text, Heading } from '@ggui-ai/design/primitives';
import type { CurrentConditionProps } from '../types';

/**
 * CurrentCondition
 * Displays the large, prominent current weather information
 * including temperature, weather condition with icon, and city name.
 */
export const CurrentCondition: React.FC<CurrentConditionProps> = ({
  city,
  temperature,
  condition,
  icon,
  unit = 'C',
}) => {
  return (
    <Stack direction="vertical" align="center" gap={16}>
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {city}
      </Text>
      <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
        {temperature}°{unit}
      </Heading>
      <Stack direction="horizontal" align="center" gap={8}>
        <span style={{ fontSize: '2em', lineHeight: 1 }}>{icon}</span>
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
          {condition}
        </Text>
      </Stack>
    </Stack>
  );
};


