import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import type { DetailsGridProps } from './types';

/**
 * DetailsGrid Component
 * Displays humidity and wind speed in a 2-column grid layout
 * with labels and decorative icons.
 */
const DetailsGrid: React.FC<DetailsGridProps> = ({
  humidity,
  humidityDisplay,
  windSpeed,
  windSpeedDisplay,
}) => {
  return (
    <Box
      padding="var(--ggui-spacing-4)"
      background="var(--ggui-color-surfaceVariant)"
      borderRadius="var(--ggui-shape-radius-md)"
      style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        gap: 'var(--ggui-spacing-4)',
        border: '1px solid var(--ggui-color-outlineVariant)',
      }}
    >
      {/* Humidity Item */}
      <Stack direction="vertical" align="center" gap={8}>
        <Text style={{ fontSize: '28px' }}>💧</Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">{humidityDisplay}</Text>
      </Stack>

      {/* Wind Speed Item */}
      <Stack direction="vertical" align="center" gap={8}>
        <Text style={{ fontSize: '28px' }}>💨</Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">{windSpeedDisplay}</Text>
      </Stack>
    </Box>
  );
};

export default DetailsGrid;

