// components/ForecastStrip.tsx
import React from 'react';
import { Stack, Divider } from '@ggui-ai/design/primitives';
import type { ForecastStripProps, ForecastDay } from '../types';
import ForecastItem from './ForecastItem';

/**
 * ForecastStrip Component
 * 
 * Renders a horizontal 5-day forecast display with individual forecast items.
 * Maps an array of ForecastDay objects into a responsive row layout.
 */
export default function ForecastStrip({ forecast, unit = 'C' }: ForecastStripProps) {
  // Handle empty forecast array
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <Stack
      direction="horizontal"
      gap={16}
      align="center"
      justify="between"
    >
      {forecast.map((day: ForecastDay, index: number) => (
        <ForecastItem
          key={index}
          day={day.day}
          icon={day.icon}
          high={day.high}
          low={day.low}
          unit={unit}
        />
      ))}
    </Stack>
  );
}


