// ui.tsx
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { CurrentCondition } from './components/CurrentCondition';
import { DetailsGrid } from './components/DetailsGrid';
import { ForecastStrip } from './components/ForecastStrip';
import { useFormatWeatherData } from './hooks';
import type { Props } from './types';

/**
 * WeatherCard Component
 * 
 * Main weather card layout that composes all sub-components (CurrentCondition,
 * DetailsGrid, ForecastStrip) and integrates with the useFormatWeatherData hook
 * for formatting weather data consistently across the UI.
 * 
 * Uses design system primitives (Card, Stack, Divider) to create a responsive,
 * theme-aware layout with proper spacing and visual hierarchy.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props): JSX.Element {
  // Format weather data using hook for consistent display strings
  const {
    conditionIcon,
    temperatureDisplay,
    humidityDisplay,
    windSpeedDisplay,
  } = useFormatWeatherData(temperature, condition, humidity, windSpeed, unit);

  return (
    <Card
      padding="var(--ggui-spacing-6)"
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant)',
        maxWidth: '600px',
      }}
    >
      <Stack gap="var(--ggui-spacing-4)">
        {/* Current Weather Conditions Section */}
        <CurrentCondition
          city={city}
          temperature={temperature}
          condition={condition}
          icon={conditionIcon}
          unit={unit}
        />
        <Divider />

        {/* Weather Details Grid Section */}
        <DetailsGrid
          humidity={humidity}
          humidityDisplay={humidityDisplay}
          windSpeed={windSpeed}
          windSpeedDisplay={windSpeedDisplay}
        />
        <Divider />

        {/* 5-Day Forecast Section */}
        <ForecastStrip forecast={forecast} unit={unit} />
      </Stack>
    </Card>
  );
}

// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  return <Component {...props} />;
}
